public enum ScanError: Swift.Error {

    
    
    case Io(msg: String
    )
    case InvalidPath
    case Snapshot(msg: String
    )
}


#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeScanError: FfiConverterRustBuffer {
    typealias SwiftType = ScanError

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> ScanError {
        let variant: Int32 = try readInt(&buf)
        switch variant {

        

        
        case 1: return .Io(
            msg: try FfiConverterString.read(from: &buf)
            )
        case 2: return .InvalidPath
        case 3: return .Snapshot(
            msg: try FfiConverterString.read(from: &buf)
            )

         default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: ScanError, into buf: inout [UInt8]) {
        switch value {

        

        
        
        case let .Io(msg):
            writeInt(&buf, Int32(1))
            FfiConverterString.write(msg, into: &buf)
            
        
        case .InvalidPath:
            writeInt(&buf, Int32(2))
        
        
        case let .Snapshot(msg):
            writeInt(&buf, Int32(3))
            FfiConverterString.write(msg, into: &buf)
            
        }
    }
}


